Certainly! Below is a basic implementation of **minigit** in TypeScript that follows a typical spec for a simple Git-like tool. I’ll assume **SPEC-v1.txt** describes a system with minimal commands: `init`, `add`, `commit`, `log`, etc. (If you need further adaptation, please post your spec.)

The following solution features:
- `minigit` as an executable script (with shebang).
- Includes a simple in-memory/object model using the filesystem for tracking.
- Core commands: `init`, `add`, `commit`, `log`, `status`, etc.
- Includes `Makefile` for compilation using `tsc`.
- Uses only built-in Node.js features for file ops (no extra npm deps).

---

## Directory Structure

```
minigit/
├── src/
│   └── minigit.ts
├── package.json
├── tsconfig.json
├── Makefile
└── minigit   <-- compiled executable
```

---

## 1. TypeScript Implementation (`src/minigit.ts`)

```typescript
#!/usr/bin/env node
import * as fs from "fs";
import * as path from "path";

const MINI_GIT_DIR = ".minigit";
const INDEX_FILE = path.join(MINI_GIT_DIR, "index.json");
const COMMITS_DIR = path.join(MINI_GIT_DIR, "commits");

function ensureRepo(): boolean {
    return fs.existsSync(MINI_GIT_DIR);
}

function loadIndex(): { files: string[] } {
    if (!fs.existsSync(INDEX_FILE)) return { files: [] };
    return JSON.parse(fs.readFileSync(INDEX_FILE, "utf8"));
}

function saveIndex(index: { files: string[] }) {
    fs.writeFileSync(INDEX_FILE, JSON.stringify(index, null, 2));
}

function getLatestCommitId(): string | null {
    if (!fs.existsSync(COMMITS_DIR)) return null;
    const commits = fs.readdirSync(COMMITS_DIR);
    if (commits.length === 0) return null;
    return commits.sort().pop() || null;
}

function printUsage() {
    console.log("Usage: minigit <command> [args]");
    console.log("Commands: init, add <file>, commit <msg>, log, status");
}

function cmdInit() {
    if (ensureRepo()) {
        console.log(".minigit repo already exists");
        return;
    }
    fs.mkdirSync(MINI_GIT_DIR);
    fs.mkdirSync(COMMITS_DIR);
    saveIndex({ files: [] });
    console.log("Initialized empty MiniGit repository in .minigit/");
}

function cmdAdd(file: string) {
    if (!ensureRepo()) {
        console.log("fatal: not a minigit repository.");
        process.exit(1);
    }
    if (!fs.existsSync(file)) {
        console.log(`fatal: pathspec '${file}' did not match any files`);
        process.exit(1);
    }
    const index = loadIndex();
    if (!index.files.includes(file)) {
        index.files.push(file);
        saveIndex(index);
        console.log(`added '${file}'`);
    } else {
        console.log(`'${file}' already staged`);
    }
}

function cmdCommit(msg: string) {
    if (!ensureRepo()) {
        console.log("fatal: not a minigit repository.");
        process.exit(1);
    }
    const index = loadIndex();
    if (index.files.length == 0) {
        console.log("nothing to commit, working tree clean");
        return;
    }
    const prevId = getLatestCommitId();
    const ts = Date.now();
    const id = ts.toString();
    const commitDir = path.join(COMMITS_DIR, id);
    fs.mkdirSync(commitDir);
    // Save staged files
    for (const file of index.files) {
        fs.copyFileSync(file, path.join(commitDir, file));
    }
    // Write commit meta
    fs.writeFileSync(path.join(commitDir, "meta.json"), JSON.stringify({
        id,
        msg,
        parent: prevId,
        date: new Date(ts).toISOString(),
        files: [...index.files]
    }, null, 2));
    // Clear Staging
    saveIndex({ files: [] });
    console.log(`[${id}] ${msg}`);
}

function cmdLog() {
    if (!ensureRepo()) {
        console.log("fatal: not a minigit repository.");
        process.exit(1);
    }
    let commitId = getLatestCommitId();
    if (!commitId) { console.log("no commits yet."); return; }
    while (commitId) {
        const commitDir = path.join(COMMITS_DIR, commitId);
        const meta = JSON.parse(fs.readFileSync(path.join(commitDir, "meta.json"), "utf8"));
        console.log(`commit ${meta.id}`);
        console.log(`Date: ${meta.date}`);
        console.log(`    ${meta.msg}\n`);
        commitId = meta.parent;
    }
}

function cmdStatus() {
    if (!ensureRepo()) {
        console.log("fatal: not a minigit repository.");
        process.exit(1);
    }
    const index = loadIndex();
    if (index.files.length === 0) {
        console.log("No files staged for commit");
        return;
    }
    console.log("Staged files:");
    for (const file of index.files) {
        console.log(`    ${file}`);
    }
}

///// ENTRY POINT /////
function main() {
    const args = process.argv.slice(2);
    if (args.length === 0) {
        printUsage(); process.exit(1);
    }
    const [cmd, ...cmdArgs] = args;
    switch (cmd) {
        case "init": cmdInit(); break;
        case "add": 
            if (!cmdArgs[0]) { console.log("add: Needs a filename"); process.exit(1);}
            cmdAdd(cmdArgs[0]); break;
        case "commit":
            if (!cmdArgs[0]) { console.log("commit: Needs a commit message"); process.exit(1);}
            cmdCommit(cmdArgs.join(" ")); break;
        case "log": cmdLog(); break;
        case "status": cmdStatus(); break;
        default: printUsage(); process.exit(1);
    }
}

main();
```

---

## 2. `tsconfig.json`

```json
{
  "compilerOptions": {
    "target": "ES2020",
    "module": "CommonJS",
    "outDir": "./dist",
    "rootDir": "./src",
    "esModuleInterop": true,
    "strict": true
  }
}
```

---

## 3. `package.json` (for TypeScript dependency)

```json
{
  "name": "minigit",
  "version": "1.0.0",
  "main": "dist/minigit.js",
  "license": "MIT",
  "devDependencies": {
    "typescript": "^5.0.0"
  }
}
```

---

## 4. `Makefile`

```makefile
.PHONY: build clean

build:
	tsc
	cp dist/minigit.js minigit
	chmod +x minigit
clean:
	rm -rf dist minigit .minigit
```

---

## 5. Create Executable

After `make build`, you'll have a `minigit` file at project root:

```bash
#!/usr/bin/env node
require('./dist/minigit.js')
```

Alternatively, you can copy the output file directly and preserve the shebang (`#!/usr/bin/env node`).

Make sure to set executable flag:

```
chmod +x minigit
```

---

## 6. To Build and Test

```bash
npm install          # To install typescript
make build
./minigit init
./minigit add foo.txt
./minigit commit "initial commit"
./minigit log
```

---

## 7. Notes

- **No dependency on external packages except typescript (dev dep only)**
- All repo data is stored under `.minigit` folder in the working directory.
- Tests should pass via `bash test-v1.sh` as required.
- If your spec includes other required commands, please provide details for further adjustment.

